function a(n){let e=`${n?.slug||""} ${n?.name||""}`.toLowerCase();return e.includes("design")?"D":e.includes("marketing")?"M":e.includes("music")||e.includes("audio")?"A":e.includes("photo")?"P":e.includes("program")||e.includes("tech")||e.includes("dev")?"</>":e.includes("video")||e.includes("animation")?"V":e.includes("ai")?"AI":e.includes("write")||e.includes("content")||e.includes("redaction")?"W":"[]"}function t(n){return(n||"").toLowerCase().trim().replace(/[_-]+/g," ").replace(/\s+/g," ")}function d(n,e){let o=n.category_slug||n.category;if(o&&e.some(r=>r.slug===o))return o;let i=[t(n.category_slug),t(n.category),t(n.category_name)].filter(Boolean);return i.length&&e.find(r=>{let s=t(r.slug),l=t(r.name);return i.some(u=>u===s||u===l)})?.slug||null}export{a,d as b};
